        require(newCost > 0, "Cost must be > 0");
        cost = newCost;
        emit CostUpdated(newCost);
    }

    // View functions
    function isWhitelisted(address user) external view returns (bool) {
        return whitelist[user];
    }

    // Mint functions
    function mintTokenWhitelisted(uint256 amount) external payable 
        requireSaleStatus(SaleStatus.Presale) 
    {
        require(whitelist[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be > 0");
        require(preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        _mint(amount, SaleStatus.Presale);
        preSaleWalletMinted[msg.sender] += amount;
    }

    function mintTokenPublic(uint256 amount) external payable 
        requireSaleStatus(SaleStatus.PublicSale) 
    {
        require(amount > 0, "Amount must be > 0");
        _mint(amount, SaleStatus.PublicSale);
    }

    // Internal mint logic
    function _mint(uint256 amount, SaleStatus saleType) internal {
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == cost * amount, "Incorrect payment");

        supply += amount;
        emit TokensMinted(msg.sender, amount, saleType);
    }
}
